def gen(rng, size):
    import string
    def w():
        return ''.join(rng.choice(string.ascii_lowercase) for _ in range(rng.randrange(1, 5)))
    items = [[w(), w(), w()] for _ in range(max(1, size))]
    key = rng.choice(['type', 'color', 'name'])
    idx = {'type': 0, 'color': 1, 'name': 2}[key]
    val = rng.choice(items)[idx] if rng.random() < 0.7 else w()
    return [items, key, val]

