class Solution:
    def countMatches(self, items, ruleKey, ruleValue):
        cnt = 0
        for it in items:
            if ruleKey == 'type' and it[0] == ruleValue:
                cnt += 1
            elif ruleKey == 'color' and it[1] == ruleValue:
                cnt += 1
            elif ruleKey == 'name' and it[2] == ruleValue:
                cnt += 1
        return cnt

